import { Kernel } from '@microsoft/semantic-kernel';
import { OpenAIEmbedding } from '@microsoft/semantic-kernel/connectors-ai-openai';

const kernel = Kernel.create();

async function auditRetrievalPrecision(query: string, retrievedDocs: Document[], groundTruth: string[], topK: number = 3): Promise<number> {
  const embeddingService = kernel.addEmbeddingService('openai-embedding', new OpenAIEmbedding('text-embedding-ada-002'));

  const queryEmbedding = await embeddingService.embedQueryAsync(query);
  const relevantEmbeddings = await embeddingService.embedQueryBatchAsync(groundTruth);

  const retrievedRelevant = retrievedDocs.slice(0, topK).filter(doc => 
    groundTruth.some(gt => doc.content.includes(gt))
  );

  return retrievedRelevant.length / topK;
}
